const tesisId = $node["Webhook"].json.body?.tesisId;
const startMs = $node["Marcar inicio"].json._startMs;

const raw = ($json.text ?? $json.output ?? $json.response ?? "").toString();

function stripFences(s) {
  return s.replace(/```json\s*/gi, "").replace(/```\s*/g, "").trim();
}

function extractFirstJsonObject(s) {
  const cleaned = stripFences(s);
  const match = cleaned.match(/\{[\s\S]*\}/);
  return match ? match[0] : cleaned;
}

let parsed;
try {
  const jsonStr = extractFirstJsonObject(raw);
  parsed = JSON.parse(jsonStr);
} catch (e) {
  parsed = {
    estado: "Error",
    puntuacionGeneral: 0,
    escalaVigesimal: "0/20",
    calificacion: "Error",
    observaciones: [
      {
        seccion: "Salida del modelo",
        estado: "Con errores",
        comentario: "La IA no devolvió un JSON parseable.",
        sugerencia: "Ajusta el prompt o conecta un parser estructurado; revisa la salida cruda."
      }
    ],
    recomendacionesFinales: "Reintenta la revisión y verifica el formato de salida (JSON)."
  };
}

if (!Array.isArray(parsed.observaciones)) parsed.observaciones = [];
if (typeof parsed.puntuacionGeneral === "string") {
  const n = parseFloat(parsed.puntuacionGeneral);
  parsed.puntuacionGeneral = Number.isFinite(n) ? n : 0;
}

const tiempoProcesamiento = typeof startMs === "number" ? Math.max(0, Math.round((Date.now() - startMs) / 1000)) : 0;

return [
  {
    json: {
      tesisId,
      tiempoProcesamiento,
      ...parsed
    }
  }
];

